+						if (table.applyCondition(row)) {
+							if (table.type.needSetProbed()) {
+								table.probedSet.set(numInBucket - 1);
+							}
+							this.instance = row;
+							return true;
+						}
+					} catch (Exception e) {
+						throw new RuntimeException("Error deserializing key or value from the hashtable: " +
+								e.getMessage(), e);
+					}
+				} else {
+					pointerOffset += BinaryHashBucketArea.POINTER_LEN;
+				}
+			}
+
+			// this segment is done. check if there is another chained bucket
+			final int forwardPointer = this.bucket.getInt(this.bucketInSegmentOffset + BinaryHashBucketArea.HEADER_FORWARD_OFFSET);
+			if (forwardPointer == BinaryHashBucketArea.BUCKET_FORWARD_POINTER_NOT_SET) {
+				this.instance = null;
+				return false;
+			}
+
+			final int overflowSegIndex = forwardPointer >>> this.segmentSizeBits;
+			this.bucket = this.overflowSegments[overflowSegIndex];
+			this.bucketInSegmentOffset = forwardPointer & this.segmentSizeMask;
+			this.pointerOffset = bucketInSegmentOffset + BinaryHashBucketArea.BUCKET_POINTER_START_OFFSET;
+			this.countInBucket = this.bucket.getShort(this.bucketInSegmentOffset + BinaryHashBucketArea.HEADER_COUNT_OFFSET);
+			this.hashCodeOffset = this.bucketInSegmentOffset + BinaryHashBucketArea.BUCKET_HEADER_LENGTH;
+			this.numInBucket = 0;
+		}
+		this.instance = null;
+		return false;
+	}
+
+	@Override
+	public BinaryRow getRow() {
