+	private static final class MyProjection implements Projection<BaseRow, BinaryRow> {
+
+		BinaryRow innerRow = new BinaryRow(1);
+		BinaryRowWriter writer = new BinaryRowWriter(innerRow);
+
+		@Override
+		public BinaryRow apply(BaseRow row) {
+			writer.reset();
